import { React, useState } from 'react'
import { Stack, Typography } from '@mui/material'
import styled from '@emotion/styled'
import { Link, Navigate, useNavigate } from 'react-router-dom'
import useAuth from '../hooks/useAuth'
import Loading from './Loading'
import supabaseClient from '../supabase'


const Img = styled("img")({ 

 })


const Login = () => {

    const { user, session, loading, setUser } = useAuth()

    const navigate = useNavigate()

    const [error, setError ] = useState()

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }


    const handleSubmit = async(e) => {

        e.preventDefault()

        setError('')

        try {

            await supabaseClient.auth.signInWithPassword(user.email, user.password)
            
            navigate('/')

        } catch(error) {

            if ( error.code === "auth/user-not-found")
            {
                setError('El usuario ingresado no existe.');
            } else if ( error.code === "auth/wrong-password")
            {
                setError('La contraseña no es correcta.');
            } else if ( error.code === "auth/internal-error")
            {
                setError('Se debe ingresar la contraseña.');
            } else if ( error.code === "auth/invalid-email")
            {
                setError('Se debe ingresar un mail válido.');
            } else
            {
                setError('Se produjo un error. Volvé a intentar más tarde.');
            }
                
        }
        
    }
    

  return (
        <>
        {   
            session != null ? <Navigate to="/" /> :
             loading ? <Loading /> : 

            <Stack>
                <img src="../img/trama.svg" alt="Trama de Biblios" />
                <img src="../img/logo-register-login.png" alt="Logo de Biblios" />
                <Typography align='center' variant="h1">¡Hola de nuevo!</Typography>
                <Typography align='center' variant="h1">Ingresá con tu usuario y contraseña</Typography>
            </Stack>
        
                        
}
        </>
  )
}

export default Login
